class Solution:
    def findSecretWord(self, words: List[str], master: 'Master') -> None:
        def match(a, b):
            return sum(x == y for x, y in zip(a, b))
        candidates = list(words)
        for _ in range(10):
            counts = {}
            for w1 in candidates:
                c = 0
                for w2 in candidates:
                    if match(w1, w2) == 0:
                        c += 1
                counts[w1] = c
            guess_word = min(candidates, key=lambda w: counts[w])
            m = master.guess(guess_word)
            if m == 6:
                return
            candidates = [w for w in candidates if match(guess_word, w) == m]

