function match(a, b) {
    let m = 0;
    for (let i = 0; i < a.length; i++) if (a[i] === b[i]) m++;
    return m;
}
var findSecretWord = function(words, master) {
    let candidates = words.slice();
    for (let round = 0; round < 10; round++) {
        const counts = new Map();
        for (const w1 of candidates) {
            let c = 0;
            for (const w2 of candidates) if (match(w1, w2) === 0) c++;
            counts.set(w1, c);
        }
        let guessWord = candidates[0];
        for (const w of candidates) if (counts.get(w) < counts.get(guessWord)) guessWord = w;
        const m = master.guess(guessWord);
        if (m === 6) return;
        candidates = candidates.filter((w) => match(guessWord, w) === m);
    }
};
